import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat result = baseFormat.withFirstRecordAsHeader();

        // The result should not be the same instance as baseFormat
        assertNotSame(baseFormat, result);

        // The header should be set (non-null)
        assertNotNull(result.getHeader());

        // The skipHeaderRecord flag should be true
        assertTrue(result.getSkipHeaderRecord());

        // The header length should be 0 (empty header) because withHeader() without arguments sets empty header
        assertEquals(0, result.getHeader().length);

        // The other properties should remain unchanged from withHeader() and withSkipHeaderRecord()
        // For example, delimiter should remain the same as default delimiter
        assertEquals(baseFormat.getDelimiter(), result.getDelimiter());
    }
}
